def _resolve_dynamic_defaults(
    ctx: Context, params: cabc.Iterable[Parameter]
) -> None:
    """Second-pass resolution for options whose default is a dynamic
    mapping keyed by other options' values. This runs after every
    parameter has been parsed, so it has access to the final value of
    any option it depends on regardless of declaration order.
    """
    params = list(params)

    for param in params:
        dynamic_default = getattr(param, "_dynamic_default", None)

        if dynamic_default is None:
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

